// TikTok scraper via Apify TikTok Scraper actor
const input = $input.first().json;
const keywords = input.keywords || [];
const runId = input.run_id;
const projectId = input.project_id;
const limit = 10;
const results = [];

try {
  // Call Apify TikTok Scraper
  const actorResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.apify.com/v2/acts/clockworks~free-tiktok-scraper/runs?waitForFinish=60',
    headers: { 'Authorization': `Bearer ${process.env.APIFY_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      hashtags: keywords.slice(0, 3),
      resultsPerPage: limit,
      shouldDownloadCovers: false,
    }),
  });

  // Get results from dataset
  const datasetId = actorResp?.data?.defaultDatasetId;
  if (datasetId) {
    const items = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.apify.com/v2/datasets/${datasetId}/items?limit=${limit}`,
      headers: { 'Authorization': `Bearer ${process.env.APIFY_TOKEN}` },
    });

    for (const item of (items || []).slice(0, limit)) {
      results.push({
        run_id: runId,
        project_id: projectId,
        source: 'tiktok',
        raw_text: item.text || item.desc || '',
        source_url: item.webVideoUrl || `https://tiktok.com/@${item.authorMeta?.name}/video/${item.id}`,
        engagement_score: (item.diggCount || 0) + ((item.commentCount || 0) * 2) + ((item.shareCount || 0) * 3),
        upvotes: item.diggCount || 0,
        comments: item.commentCount || 0,
        shares: item.shareCount || 0,
        posted_at: item.createTime ? new Date(item.createTime * 1000).toISOString() : null,
        metadata: { hashtags: item.hashtags?.map(h => h.name) || [], author: item.authorMeta?.name },
      });
    }
  }
} catch (e) {
  return [{ json: { source: 'tiktok', success: false, error: e.message, count: 0 } }];
}

if (results.length > 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.SUPABASE_URL}/rest/v1/research_results`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify(results),
  });
}

return [{ json: { source: 'tiktok', success: true, count: results.length } }];
